import java.io.*;
import java.util.*;

public class Main {
    private static boolean startsWithVowel(String w) {
        if (w.isEmpty()) return false;
        char c = Character.toLowerCase(w.charAt(0));
        return c=='a' || c=='e' || c=='i' || c=='o' || c=='u';
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String sentence = br.readLine();
            if (sentence == null) sentence = "";
            StringTokenizer st = new StringTokenizer(sentence);
            boolean first = true;
            while (st.hasMoreTokens()) {
                String w = st.nextToken();
                if (!startsWithVowel(w)) {
                    if (!first) sb.append(' ');
                    sb.append(w);
                    first = false;
                }
            }
            sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def starts_with_vowel(word: str) -> bool:
    return word and word[0].lower() in 'aeiou'

def remove_vowel_words(sentence: str) -> str:
    return ' '.join(w for w in sentence.split() if not starts_with_vowel(w))

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        line = data[i] if i < len(data) else ''
        out.append(remove_vowel_words(line))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

